using System.ComponentModel.DataAnnotations;

namespace sv_fe459e8439ea4cba90c0077f1d6cd996.Models;

public class AppointmentModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string Doctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required.")]
    public DateOnly? Date { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string ReasonForVisit { get; set; } = string.Empty;
}

namespace sv_fe459e8439ea4cba90c0077f1d6cd996.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Williams",
            "Dr. Brown"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return fixed slots regardless of doctor/date
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    /// <summary>
    /// Validates patient data against server-side business rules.
    /// Returns a dictionary of field name → error message for any failures.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(Models.AppointmentModel.Email)] = "Account has outstanding balance.";
        }

        // Reject self-pay for doctors that don't accept it
        if (insuranceProvider == "None" && doctor == "Dr. Smith")
        {
            errors[nameof(Models.AppointmentModel.Doctor)] = "Selected doctor does not accept self-pay patients.";
        }

        // Simulate race condition on a specific slot
        if (timeSlot == "10:00 AM")
        {
            errors[nameof(Models.AppointmentModel.TimeSlot)] = "This slot is no longer available.";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_fe459e8439ea4cba90c0077f1d6cd996.Models
@using sv_fe459e8439ea4cba90c0077f1d6cd996.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book an Appointment</h3>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="appointment">
    <DataAnnotationsValidator />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* ───── STEP 2 ───── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.Date" @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => Model.Date" />
                @if (dateError is not null)
                {
                    <div class="text-danger">@dateError</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeslot">Time Slot</label>
                <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="Model.ReasonForVisit" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <div class="d-flex gap-2">
                <button type="button" class="btn btn-outline-secondary" @onclick="BackToStep1">
                    Back
                </button>
                <button type="button" class="btn btn-primary" @onclick="CheckAvailability" disabled="@isSubmitting">
                    Check Availability
                </button>
            </div>
        </fieldset>
    }

    @if (isConfirmed)
    {
        <div class="alert alert-success mt-4">
            Appointment booked successfully!
        </div>
    }
</EditForm>

@code {
    private AppointmentModel Model { get; set; } = new();
    private EditContext editContext = default!;
    private ValidationMessageStore messageStore = default!;

    private bool showStep2;
    private bool isSubmitting;
    private bool isConfirmed;
    private string? dateError;

    private List<string> doctors = new();
    private List<string> timeSlots = new();

    // Fields that belong to step 1 for partial validation
    private static readonly string[] Step1Fields =
    {
        nameof(AppointmentModel.PatientName),
        nameof(AppointmentModel.Email),
        nameof(AppointmentModel.Phone),
        nameof(AppointmentModel.InsuranceProvider)
    };

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        messageStore = new ValidationMessageStore(editContext);
        editContext.OnFieldChanged += (_, args) =>
        {
            messageStore.Clear(args.FieldIdentifier);
            editContext.NotifyValidationStateChanged();
        };

        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Clear previous custom messages so they don't interfere
        messageStore.Clear();

        // Run full validation then check only step-1 fields
        editContext.Validate();
        var step1Valid = !editContext.GetValidationMessages()
            .Any() || editContext.GetValidationMessages()
            .All(msg =>
            {
                // Only care about step-1 field errors
                return !Step1Fields.Any(f =>
                    editContext.GetValidationMessages(
                        new FieldIdentifier(Model, f)).Contains(msg));
            });

        // More precise: check each step-1 field individually
        var hasStep1Error = Step1Fields.Any(f =>
            editContext.GetValidationMessages(new FieldIdentifier(Model, f)).Any());

        if (!hasStep1Error)
        {
            showStep2 = true;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
    }

    private async Task OnDateChanged()
    {
        dateError = null;
        timeSlots.Clear();
        Model.TimeSlot = string.Empty;

        if (Model.Date is not null)
        {
            if (Model.Date <= DateOnly.FromDateTime(DateTime.Today))
            {
                dateError = "Date must be in the future.";
                return;
            }

            timeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.Doctor, Model.Date.Value);
        }
    }

    private async Task CheckAvailability()
    {
        messageStore.Clear();
        dateError = null;

        // Validate all fields via DataAnnotations first
        if (!editContext.Validate())
            return;

        // Custom future-date rule
        if (Model.Date is not null && Model.Date <= DateOnly.FromDateTime(DateTime.Today))
        {
            dateError = "Date must be in the future.";
            return;
        }

        isSubmitting = true;

        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                Model.Email, Model.InsuranceProvider, Model.Doctor, Model.TimeSlot);

            if (errors.Count > 0)
            {
                foreach (var (field, message) in errors)
                {
                    messageStore.Add(new FieldIdentifier(Model, field), message);
                }
                editContext.NotifyValidationStateChanged();
                return;
            }

            // All validations passed — submit
            isConfirmed = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private async Task HandleSubmit()
    {
        await CheckAvailability();
    }
}

